You are implementing Task 29: Public API for Integrations in a loyalty card app.

**Working directory:** C:\Users\User\loyalty-app

**What to do:**

### 1. Create API keys migration

Check existing migrations in `supabase/migrations/` and use the next available number.

```sql
create table public.api_keys (
  id uuid primary key default uuid_generate_v4(),
  merchant_id uuid references merchants(id) on delete cascade not null,
  key_hash text not null,
  name text not null,
  last_used_at timestamptz,
  is_active boolean default true,
  created_at timestamptz default now()
);

alter table public.api_keys enable row level security;
create policy "API keys: merchant owner" on public.api_keys
  for all using (merchant_id in (select id from merchants where user_id = auth.uid()));
```

### 2. Create `supabase/functions/api-v1/index.ts`

An Edge Function that provides REST API endpoints authenticated by API key:

- Parse the URL path after `/api-v1/` to determine the endpoint
- Authenticate via `X-API-Key` header — hash the key with SHA-256 and look up in `api_keys` table
- Only allow if merchant plan is 'business'
- Update `last_used_at` on each use

Endpoints:
- `GET /programs` — List merchant's loyalty programs
- `GET /clients` — List merchant's clients (via customer_cards)
- `POST /stamps` — Add stamp to a customer card: `{ card_id, count: 1 }`
- `POST /points` — Add points to a customer card: `{ card_id, points }`
- `GET /analytics` — Get merchant KPIs from the merchant_kpis view

```typescript
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type, x-api-key',
};

async function hashKey(key: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(key);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, '0')).join('');
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    // Authenticate via API key
    const apiKey = req.headers.get('X-API-Key');
    if (!apiKey) return new Response(JSON.stringify({ error: 'Missing API key' }), { status: 401, headers: corsHeaders });

    const keyHash = await hashKey(apiKey);
    const { data: keyRecord } = await supabase
      .from('api_keys')
      .select('*, merchants(plan)')
      .eq('key_hash', keyHash)
      .eq('is_active', true)
      .single();

    if (!keyRecord) return new Response(JSON.stringify({ error: 'Invalid API key' }), { status: 401, headers: corsHeaders });
    if ((keyRecord as any).merchants?.plan !== 'business') {
      return new Response(JSON.stringify({ error: 'Business plan required' }), { status: 403, headers: corsHeaders });
    }

    const merchantId = keyRecord.merchant_id;

    // Update last_used_at
    await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRecord.id);

    // Route requests
    const url = new URL(req.url);
    const path = url.pathname.replace(/^\/api-v1\/?/, '').replace(/\/$/, '');
    const method = req.method;

    const json = (data: any, status = 200) => new Response(JSON.stringify(data), {
      status, headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });

    if (method === 'GET' && path === 'programs') {
      const { data } = await supabase.from('loyalty_programs').select('*').eq('merchant_id', merchantId);
      return json({ data });
    }

    if (method === 'GET' && path === 'clients') {
      const { data } = await supabase
        .from('customer_cards')
        .select('*, customers(*), loyalty_programs!inner(merchant_id)')
        .eq('loyalty_programs.merchant_id', merchantId);
      return json({ data });
    }

    if (method === 'POST' && path === 'stamps') {
      const body = await req.json();
      if (!body.card_id) return json({ error: 'Missing card_id' }, 400);
      const count = body.count ?? 1;

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
        .single();
      if (!card) return json({ error: 'Card not found' }, 404);

      await supabase.from('customer_cards').update({
        current_stamps: card.current_stamps + count,
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id, type: 'stamp_add', value: count, validated_by: 'manual',
      });

      return json({ success: true });
    }

    if (method === 'POST' && path === 'points') {
      const body = await req.json();
      if (!body.card_id || !body.points) return json({ error: 'Missing card_id or points' }, 400);

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
        .single();
      if (!card) return json({ error: 'Card not found' }, 404);

      await supabase.from('customer_cards').update({
        current_points: card.current_points + body.points,
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id, type: 'points_add', value: body.points, validated_by: 'manual',
      });

      return json({ success: true });
    }

    if (method === 'GET' && path === 'analytics') {
      const { data } = await supabase.from('merchant_kpis').select('*').eq('merchant_id', merchantId).single();
      return json({ data });
    }

    return json({ error: 'Not found' }, 404);

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});
```

### 3. Create `apps/dashboard/src/app/(dashboard)/settings/api/page.tsx`

A client component that:
- Shows a list of existing API keys (name, created_at, last_used_at, active status) — key_hash is NOT displayed
- "Generate New Key" form: enter a name, click generate
  - Generate a random key (e.g., `lk_` + 32 random hex chars)
  - Hash it with SHA-256, store the hash in the DB
  - Show the key ONCE to the user with a copy button and a warning "This key will only be shown once"
- Revoke button to deactivate keys
- If merchant plan is not 'business', show a message directing them to upgrade

### 4. Commit

```bash
git add .
git commit -m "feat: add public REST API with API key auth"
```

**Important:**
- Read existing files before modifying
- Use existing shadcn/ui components
- The merchant_kpis view was created in migration 003
- Do NOT skip the commit

