-- API Keys for public REST API
create table public.api_keys (
  id uuid primary key default uuid_generate_v4(),
  merchant_id uuid references merchants(id) on delete cascade not null,
  key_hash text not null,
  name text not null,
  last_used_at timestamptz,
  is_active boolean default true,
  created_at timestamptz default now()
);

create index idx_api_keys_merchant on public.api_keys(merchant_id);
create index idx_api_keys_hash on public.api_keys(key_hash);

alter table public.api_keys enable row level security;

create policy "API keys: merchant owner" on public.api_keys
  for all using (merchant_id in (select id from merchants where user_id = auth.uid()));

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers':
    'authorization, x-client-info, apikey, content-type, x-api-key',
};

async function hashKey(key: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(key);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    // Authenticate via API key
    const apiKey = req.headers.get('X-API-Key');
    if (!apiKey) {
      return new Response(JSON.stringify({ error: 'Missing API key' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });
    }

    const keyHash = await hashKey(apiKey);
    const { data: keyRecord } = await supabase
      .from('api_keys')
      .select('*, merchants(plan)')
      .eq('key_hash', keyHash)
      .eq('is_active', true)
      .single();

    if (!keyRecord) {
      return new Response(JSON.stringify({ error: 'Invalid API key' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });
    }

    if ((keyRecord as any).merchants?.plan !== 'business') {
      return new Response(
        JSON.stringify({ error: 'Business plan required' }),
        {
          status: 403,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        }
      );
    }

    const merchantId = keyRecord.merchant_id;

    // Update last_used_at
    await supabase
      .from('api_keys')
      .update({ last_used_at: new Date().toISOString() })
      .eq('id', keyRecord.id);

    // Route requests
    const url = new URL(req.url);
    const path = url.pathname.replace(/^\/api-v1\/?/, '').replace(/\/$/, '');
    const method = req.method;

    const json = (data: any, status = 200) =>
      new Response(JSON.stringify(data), {
        status,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });

    // GET /programs — List merchant's loyalty programs
    if (method === 'GET' && path === 'programs') {
      const { data } = await supabase
        .from('loyalty_programs')
        .select('*')
        .eq('merchant_id', merchantId);
      return json({ data });
    }

    // GET /clients — List merchant's clients via customer_cards
    if (method === 'GET' && path === 'clients') {
      const { data } = await supabase
        .from('customer_cards')
        .select('*, customers(*), loyalty_programs!inner(merchant_id)')
        .eq('loyalty_programs.merchant_id', merchantId);
      return json({ data });
    }

    // POST /stamps — Add stamp to a customer card
    if (method === 'POST' && path === 'stamps') {
      const body = await req.json();
      if (!body.card_id) return json({ error: 'Missing card_id' }, 400);
      const count = body.count ?? 1;

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
        .single();
      if (!card) return json({ error: 'Card not found' }, 404);

      await supabase
        .from('customer_cards')
        .update({
          current_stamps: card.current_stamps + count,
          last_activity: new Date().toISOString(),
        })
        .eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id,
        type: 'stamp_add',
        value: count,
        validated_by: 'manual',
      });

      return json({ success: true });
    }

    // POST /points — Add points to a customer card
    if (method === 'POST' && path === 'points') {
      const body = await req.json();
      if (!body.card_id || !body.points) {
        return json({ error: 'Missing card_id or points' }, 400);
      }

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
        .single();
      if (!card) return json({ error: 'Card not found' }, 404);

      await supabase
        .from('customer_cards')
        .update({
          current_points: card.current_points + body.points,
          last_activity: new Date().toISOString(),
        })
        .eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id,
        type: 'points_add',
        value: body.points,
        validated_by: 'manual',
      });

      return json({ success: true });
    }

    // GET /analytics — Get merchant KPIs
    if (method === 'GET' && path === 'analytics') {
      const { data } = await supabase
        .from('merchant_kpis')
        .select('*')
        .eq('merchant_id', merchantId)
        .single();
      return json({ data });
    }

    return json({ error: 'Not found' }, 404);
  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }
});

'use client';

import { useEffect, useState, useCallback } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';

interface ApiKey {
  id: string;
  name: string;
  last_used_at: string | null;
  is_active: boolean;
  created_at: string;
}

async function hashKey(key: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(key);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

function generateApiKey(): string {
  const bytes = new Uint8Array(16);
  crypto.getRandomValues(bytes);
  const hex = Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
  return `lk_${hex}`;
}

export default function ApiKeysPage() {
  const supabase = createClient();
  const [apiKeys, setApiKeys] = useState<ApiKey[]>([]);
  const [merchantId, setMerchantId] = useState<string | null>(null);
  const [merchantPlan, setMerchantPlan] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [newKeyName, setNewKeyName] = useState('');
  const [generatedKey, setGeneratedKey] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);

  const fetchApiKeys = useCallback(
    async (mId: string) => {
      const { data } = await supabase
        .from('api_keys')
        .select('id, name, last_used_at, is_active, created_at')
        .eq('merchant_id', mId)
        .order('created_at', { ascending: false });
      setApiKeys(data ?? []);
    },
    [supabase]
  );

  useEffect(() => {
    async function init() {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (!user) return;
      const { data: merchant } = await supabase
        .from('merchants')
        .select('id, plan')
        .eq('user_id', user.id)
        .single();
      if (!merchant) return;
      setMerchantId(merchant.id);
      setMerchantPlan(merchant.plan);
      await fetchApiKeys(merchant.id);
      setLoading(false);
    }
    init();
  }, [supabase, fetchApiKeys]);

  async function handleGenerate() {
    if (!merchantId || !newKeyName.trim()) return;
    setGenerating(true);

    const rawKey = generateApiKey();
    const keyHash = await hashKey(rawKey);

    const { error } = await supabase.from('api_keys').insert({
      merchant_id: merchantId,
      key_hash: keyHash,
      name: newKeyName.trim(),
    });

    if (error) {
      console.error('Failed to create API key:', error.message);
      setGenerating(false);
      return;
    }

    setGeneratedKey(rawKey);
    setCopied(false);
    setNewKeyName('');
    await fetchApiKeys(merchantId);
    setGenerating(false);
  }

  async function handleRevoke(keyId: string) {
    if (!confirm('Are you sure you want to revoke this API key? This cannot be undone.'))
      return;
    const { error } = await supabase
      .from('api_keys')
      .update({ is_active: false })
      .eq('id', keyId);
    if (error) {
      console.error('Failed to revoke API key:', error.message);
    } else if (merchantId) {
      await fetchApiKeys(merchantId);
    }
  }

  function handleCopy() {
    if (generatedKey) {
      navigator.clipboard.writeText(generatedKey);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  }

  function handleDialogClose(open: boolean) {
    setDialogOpen(open);
    if (!open) {
      setGeneratedKey(null);
      setNewKeyName('');
      setCopied(false);
    }
  }

  if (loading) {
    return <p className="text-gray-500">Loading API settings...</p>;
  }

  if (merchantPlan !== 'business') {
    return (
      <div>
        <h2 className="text-2xl font-bold mb-6">API Keys</h2>
        <Card>
          <CardContent className="py-12 text-center">
            <h3 className="text-lg font-semibold mb-2">Business Plan Required</h3>
            <p className="text-gray-500 mb-4">
              The Public API is available exclusively on the Business plan. Upgrade your
              subscription to access API key management and integrate with external
              systems.
            </p>
            <Button asChild>
              <a href="/settings/billing">Upgrade to Business</a>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">API Keys</h2>
        <Dialog open={dialogOpen} onOpenChange={handleDialogClose}>
          <DialogTrigger asChild>
            <Button>Generate New Key</Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>
                {generatedKey ? 'API Key Generated' : 'Generate New API Key'}
              </DialogTitle>
              <DialogDescription>
                {generatedKey
                  ? 'Copy this key now. It will only be shown once and cannot be retrieved later.'
                  : 'Give your API key a descriptive name to identify its usage.'}
              </DialogDescription>
            </DialogHeader>

            {generatedKey ? (
              <div className="space-y-4">
                <div className="rounded-md border bg-muted p-4">
                  <code className="text-sm break-all select-all">{generatedKey}</code>
                </div>
                <div className="flex items-center gap-2">
                  <Button onClick={handleCopy} variant="outline" className="w-full">
                    {copied ? 'Copied!' : 'Copy to Clipboard'}
                  </Button>
                </div>
                <p className="text-sm text-destructive font-medium">
                  Warning: This key will only be shown once. Store it securely.
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                <div>
                  <Label htmlFor="key-name">Key Name</Label>
                  <Input
                    id="key-name"
                    value={newKeyName}
                    onChange={(e) => setNewKeyName(e.target.value)}
                    placeholder="e.g. POS Integration, Mobile App"
                  />
                </div>
              </div>
            )}

            <DialogFooter>
              {!generatedKey && (
                <Button
                  onClick={handleGenerate}
                  disabled={generating || !newKeyName.trim()}
                >
                  {generating ? 'Generating...' : 'Generate Key'}
                </Button>
              )}
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Your API Keys</CardTitle>
        </CardHeader>
        <CardContent>
          {apiKeys.length === 0 ? (
            <p className="text-gray-500 py-4 text-center">
              No API keys yet. Generate your first key to get started with the API.
            </p>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Created</TableHead>
                  <TableHead>Last Used</TableHead>
                  <TableHead className="text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {apiKeys.map((key) => (
                  <TableRow key={key.id}>
                    <TableCell className="font-medium">{key.name}</TableCell>
                    <TableCell>
                      <Badge variant={key.is_active ? 'default' : 'secondary'}>
                        {key.is_active ? 'Active' : 'Revoked'}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      {new Date(key.created_at).toLocaleDateString()}
                    </TableCell>
                    <TableCell>
                      {key.last_used_at
                        ? new Date(key.last_used_at).toLocaleDateString()
                        : 'Never'}
                    </TableCell>
                    <TableCell className="text-right">
                      {key.is_active && (
                        <Button
                          variant="destructive"
                          size="sm"
                          onClick={() => handleRevoke(key.id)}
                        >
                          Revoke
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <Card className="mt-6">
        <CardHeader>
          <CardTitle>API Documentation</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-gray-500 mb-4">
            Use your API key by including it in the <code className="bg-muted px-1 py-0.5 rounded text-xs">X-API-Key</code> header of your requests.
          </p>
          <div className="space-y-3 text-sm">
            <div>
              <p className="font-medium">Available Endpoints:</p>
              <ul className="list-disc list-inside mt-1 space-y-1 text-gray-600">
                <li><code className="bg-muted px-1 py-0.5 rounded text-xs">GET /programs</code> — List your loyalty programs</li>
                <li><code className="bg-muted px-1 py-0.5 rounded text-xs">GET /clients</code> — List your clients</li>
                <li><code className="bg-muted px-1 py-0.5 rounded text-xs">POST /stamps</code> — Add stamps to a card</li>
                <li><code className="bg-muted px-1 py-0.5 rounded text-xs">POST /points</code> — Add points to a card</li>
                <li><code className="bg-muted px-1 py-0.5 rounded text-xs">GET /analytics</code> — Get your KPIs</li>
              </ul>
            </div>
            <div>
              <p className="font-medium">Example Request:</p>
              <pre className="bg-muted rounded-md p-3 mt-1 overflow-x-auto text-xs">
{`curl -H "X-API-Key: lk_your_key_here" \\
  https://your-project.supabase.co/functions/v1/api-v1/programs`}
              </pre>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
